import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';

function EditarOS() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [form, setForm] = useState({ equipamento: '', modelo: '', imei: '', defeito: '', preco_final: '', tipo_atendimento: 'presencial' });

  useEffect(() => {
    carregarOS();
  }, []);

  const carregarOS = async () => {
    try {
      const res = await api.get(`/os/${id}`);
      setForm(res.data);
    } catch (err) {
      alert('Erro ao carregar OS');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await api.put(`/os/${id}`, form);
      alert('OS atualizada com sucesso!');
      navigate(`/os/${id}`);
    } catch (err) {
      alert('Erro ao atualizar');
    }
  };

  return (
    <div style={{ maxWidth: '600px', margin: '0 auto', background: 'white', padding: '20px', borderRadius: '12px' }}>
      <h2>Editar OS #{id}</h2>
      <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
        <input type="text" placeholder="Equipamento" value={form.equipamento || ''} onChange={e => setForm({...form, equipamento: e.target.value})} />
        <input type="text" placeholder="Modelo" value={form.modelo || ''} onChange={e => setForm({...form, modelo: e.target.value})} />
        <input type="text" placeholder="IMEI" value={form.imei || ''} onChange={e => setForm({...form, imei: e.target.value})} />
        <textarea placeholder="Defeito relatado" value={form.defeito || ''} onChange={e => setForm({...form, defeito: e.target.value})} rows="3" />
        <input type="number" step="0.01" placeholder="Preço final" value={form.preco_final || ''} onChange={e => setForm({...form, preco_final: e.target.value})} />
        <select value={form.tipo_atendimento} onChange={e => setForm({...form, tipo_atendimento: e.target.value})}>
          <option value="presencial">Presencial</option>
          <option value="remoto">Remoto</option>
        </select>
        <button type="submit" style={{ padding: '10px', background: '#007bff', color: 'white', border: 'none', borderRadius: '5px' }}>Salvar alterações</button>
      </form>
    </div>
  );
}

export default EditarOS;
